// src/pages/ApplyLeave.js
import React, { useState } from 'react';
import { useApp } from '../context/AppContext';

const DEPARTMENTS = [
  'Computer Engineering',
  'Mechanical Engineering',
  'Civil Engineering',
  'Electrical Engineering',
  'Electronics & Telecommunication',
  'Information Technology',
];

const LEAVE_TYPES = [
  { value: 'medical', label: '🏥 Medical Leave' },
  { value: 'casual', label: '🌴 Casual Leave' },
  { value: 'duty', label: '📋 Duty Leave' },
  { value: 'personal', label: '👤 Personal Leave' },
];

export default function ApplyLeave({ setActivePage }) {
  const { applyLeave, getTeacherSlots, currentUser, staff } = useApp();

  const [form, setForm] = useState({
    facultyId: currentUser?.id || '',
    department: '',
    leaveType: '',
    fromDate: '',
    toDate: '',
    reason: '',
  });
  const [preview, setPreview] = useState(null);
  const [submitted, setSubmitted] = useState(false);

  // Selected faculty
  const selectedFaculty = staff.find(s => s.id === parseInt(form.facultyId));

  const handlePreview = () => {
    if (!form.facultyId || !form.department || !form.leaveType || !form.fromDate || !form.toDate || !form.reason) {
      alert('Please fill all fields');
      return;
    }
    const slots = getTeacherSlots(parseInt(form.facultyId), form.fromDate, form.toDate);
    setPreview(slots);
  };

  const handleSubmit = () => {
    applyLeave(parseInt(form.facultyId), form.fromDate, form.toDate, `[${LEAVE_TYPES.find(l => l.value === form.leaveType)?.label}] ${form.reason}`);
    setSubmitted(true);
    setTimeout(() => setActivePage('My Leaves'), 2000);
  };

  if (submitted) {
    return (
      <div style={styles.container}>
        <div style={styles.successBox}>
          <div style={styles.successIcon}>🎉</div>
          <h2 style={styles.successTitle}>Leave Request Submitted!</h2>
          <p style={styles.successMsg}>
            Your leave request has been submitted. Free staff have been notified for substitute requests.
          </p>
          <p style={{ color: '#64748b', fontSize: 14 }}>Redirecting to My Leaves...</p>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>📝 Apply for Leave</h1>
      <p style={styles.subtitle}>Fill in the details below to submit your leave request.</p>

      <div style={styles.card}>

        {/* Row 1: Faculty Name + Department */}
        <div style={styles.row}>
          <div style={styles.formGroup}>
            <label style={styles.label}>Faculty Name *</label>
                      </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Department *</label>
            <select
              style={styles.select}
              value={form.department}
              onChange={e => setForm({ ...form, department: e.target.value })}
            >
              <option value="">-- Select Department --</option>
              {DEPARTMENTS.map(d => (
                <option key={d} value={d}>{d}</option>
              ))}
            </select>
          </div>
        </div>

        {/* Row 2: Leave Type */}
        <div style={styles.formGroup}>
          <label style={styles.label}>Leave Type *</label>
          <div style={styles.leaveTypeGrid}>
            {LEAVE_TYPES.map(lt => (
              <div
                key={lt.value}
                style={{
                  ...styles.leaveTypeCard,
                  ...(form.leaveType === lt.value ? styles.leaveTypeCardActive : {}),
                }}
                onClick={() => setForm({ ...form, leaveType: lt.value })}
              >
                {lt.label}
              </div>
            ))}
          </div>
        </div>

        {/* Row 3: From Date + To Date */}
        <div style={styles.row}>
          <div style={styles.formGroup}>
            <label style={styles.label}>From Date *</label>
            <input
              type="date"
              style={styles.input}
              value={form.fromDate}
              onChange={e => { setForm({ ...form, fromDate: e.target.value }); setPreview(null); }}
              min={new Date().toISOString().split('T')[0]}
            />
          </div>
          <div style={styles.formGroup}>
            <label style={styles.label}>To Date *</label>
            <input
              type="date"
              style={styles.input}
              value={form.toDate}
              onChange={e => { setForm({ ...form, toDate: e.target.value }); setPreview(null); }}
              min={form.fromDate || new Date().toISOString().split('T')[0]}
            />
          </div>
        </div>

        {/* Row 4: Reason */}
        <div style={styles.formGroup}>
          <label style={styles.label}>Reason for Leave *</label>
          <textarea
            style={styles.textarea}
            rows={3}
            placeholder="Enter reason for leave..."
            value={form.reason}
            onChange={e => setForm({ ...form, reason: e.target.value })}
          />
        </div>

        <button style={styles.previewBtn} onClick={handlePreview}>
          🔍 Preview Affected Classes & Substitutes
        </button>
      </div>

      {/* Preview Section */}
      {preview && (
        <div style={styles.previewSection}>
          {/* Summary Box */}
          <div style={styles.summaryBox}>
            <h3 style={styles.summaryTitle}>📄 Leave Request Summary</h3>
            <div style={styles.summaryGrid}>
              <div style={styles.summaryItem}><span style={styles.summaryKey}>Faculty</span><span style={styles.summaryVal}>{selectedFaculty?.name}</span></div>
              <div style={styles.summaryItem}><span style={styles.summaryKey}>Department</span><span style={styles.summaryVal}>{form.department}</span></div>
              <div style={styles.summaryItem}><span style={styles.summaryKey}>Leave Type</span><span style={styles.summaryVal}>{LEAVE_TYPES.find(l => l.value === form.leaveType)?.label}</span></div>
              <div style={styles.summaryItem}><span style={styles.summaryKey}>Duration</span><span style={styles.summaryVal}>{form.fromDate} → {form.toDate}</span></div>
              <div style={{ ...styles.summaryItem, gridColumn: '1 / -1' }}><span style={styles.summaryKey}>Reason</span><span style={styles.summaryVal}>{form.reason}</span></div>
            </div>
          </div>

          <h2 style={styles.previewTitle}>
            {preview.length === 0 ? '✅ No Classes Affected' : `📋 ${preview.length} Classes Affected`}
          </h2>

          {preview.length > 0 && (
            <div style={styles.slotGrid}>
              {preview.map((slot, i) => (
                <div key={i} style={styles.slotCard}>
                  <div style={styles.slotHeader}>
                    <span style={styles.slotDay}>{slot.day}, {slot.date}</span>
                    <span style={styles.slotPeriod}>Period {slot.period}</span>
                  </div>
                  <div style={styles.slotDetails}>
                    <span>🕐 {slot.time}</span>
                    <span>🏫 Class {slot.class}</span>
                  </div>
                  <div style={styles.subsSection}>
                    <div style={styles.subsLabel}>Available Free Teachers:</div>
                    {slot.freeTeachers.length === 0 ? (
                      <div style={styles.noSub}>⚠️ No free teacher available</div>
                    ) : (
                      <div style={styles.subsList}>
                        {slot.freeTeachers.slice(0, 3).map(t => (
                          <span key={t.id} style={styles.subChip}>✅ {t.name}</span>
                        ))}
                        {slot.freeTeachers.length > 3 && <span style={styles.moreChip}>+{slot.freeTeachers.length - 3} more</span>}
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}

          <button style={styles.submitBtn} onClick={handleSubmit}>
            ✅ Confirm & Submit Leave Request
          </button>
        </div>
      )}
    </div>
  );
}

const styles = {
  container: { padding: 32, maxWidth: 900, margin: '0 auto' },
  title: { fontSize: 28, fontWeight: 800, color: '#1e293b', margin: 0 },
  subtitle: { color: '#64748b', marginTop: 8, marginBottom: 28, fontSize: 15 },
  card: { background: '#fff', borderRadius: 20, padding: 32, boxShadow: '0 4px 24px rgba(0,0,0,0.07)', marginBottom: 24, border: '1px solid #f1f5f9' },
  row: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20 },
  formGroup: { marginBottom: 20 },
  label: { display: 'block', fontWeight: 600, color: '#374151', marginBottom: 8, fontSize: 14 },
  input: { width: '100%', padding: '12px 16px', borderRadius: 10, border: '1.5px solid #e2e8f0', fontSize: 14, outline: 'none', color: '#1e293b', boxSizing: 'border-box' },
  select: { width: '100%', padding: '12px 16px', borderRadius: 10, border: '1.5px solid #e2e8f0', fontSize: 14, outline: 'none', color: '#1e293b', background: '#fff', cursor: 'pointer', boxSizing: 'border-box' },
  textarea: { width: '100%', padding: '12px 16px', borderRadius: 10, border: '1.5px solid #e2e8f0', fontSize: 14, outline: 'none', resize: 'vertical', color: '#1e293b', boxSizing: 'border-box' },

  // Leave Type Cards
  leaveTypeGrid: { display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 12 },
  leaveTypeCard: {
    padding: '12px 10px', borderRadius: 10, border: '2px solid #e2e8f0',
    textAlign: 'center', cursor: 'pointer', fontSize: 13, fontWeight: 600,
    color: '#64748b', background: '#f8fafc', transition: 'all 0.2s',
  },
  leaveTypeCardActive: {
    border: '2px solid #667eea', background: '#eef2ff', color: '#4338ca',
    boxShadow: '0 2px 12px rgba(102,126,234,0.2)',
  },

  previewBtn: { background: '#667eea', color: '#fff', border: 'none', padding: '12px 28px', borderRadius: 12, cursor: 'pointer', fontSize: 15, fontWeight: 600 },

  // Summary
  previewSection: { marginTop: 16 },
  summaryBox: { background: '#fff', borderRadius: 16, padding: 24, marginBottom: 24, border: '1px solid #e2e8f0', boxShadow: '0 2px 12px rgba(0,0,0,0.05)' },
  summaryTitle: { fontSize: 16, fontWeight: 700, color: '#1e293b', marginBottom: 16, marginTop: 0 },
  summaryGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 },
  summaryItem: { display: 'flex', flexDirection: 'column', gap: 2 },
  summaryKey: { fontSize: 12, color: '#94a3b8', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.05em' },
  summaryVal: { fontSize: 14, color: '#1e293b', fontWeight: 600 },

  previewTitle: { fontSize: 20, fontWeight: 700, color: '#1e293b', marginBottom: 16 },
  slotGrid: { display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: 16, marginBottom: 20 },
  slotCard: { background: '#fff', borderRadius: 16, padding: 20, boxShadow: '0 2px 16px rgba(0,0,0,0.06)', border: '1px solid #e2e8f0' },
  slotHeader: { display: 'flex', justifyContent: 'space-between', marginBottom: 10 },
  slotDay: { fontWeight: 700, color: '#1e293b', fontSize: 14 },
  slotPeriod: { background: '#dbeafe', color: '#1d4ed8', borderRadius: 20, padding: '3px 12px', fontSize: 12, fontWeight: 600 },
  slotDetails: { display: 'flex', gap: 16, color: '#64748b', fontSize: 13, marginBottom: 12 },
  subsSection: {},
  subsLabel: { fontWeight: 600, color: '#374151', fontSize: 13, marginBottom: 8 },
  noSub: { background: '#fef2f2', color: '#dc2626', borderRadius: 8, padding: '8px 12px', fontSize: 13 },
  subsList: { display: 'flex', flexWrap: 'wrap', gap: 6 },
  subChip: { background: '#f0fdf4', color: '#166534', borderRadius: 20, padding: '4px 10px', fontSize: 12, fontWeight: 500 },
  moreChip: { background: '#f1f5f9', color: '#64748b', borderRadius: 20, padding: '4px 10px', fontSize: 12 },
  submitBtn: { background: '#10b981', color: '#fff', border: 'none', padding: '14px 36px', borderRadius: 12, cursor: 'pointer', fontSize: 16, fontWeight: 700, width: '100%' },
  successBox: { background: '#fff', borderRadius: 24, padding: 60, textAlign: 'center', boxShadow: '0 8px 40px rgba(0,0,0,0.08)', maxWidth: 500, margin: '80px auto' },
  successIcon: { fontSize: 64, marginBottom: 16 },
  successTitle: { fontSize: 24, fontWeight: 800, color: '#1e293b', marginBottom: 12 },
  successMsg: { color: '#64748b', fontSize: 15, lineHeight: 1.6 },
};
